#include<bits/stdc++.h>
using namespace std;
int p[22000010];
char s[22000010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%s",s+1);
        int n=strlen(s+1);
        for(int i=0;i<=n+1;i++)
        {
            p[i]=0;
        }
        s[n+1]='@';
        s[n+2]='#';
        int ans=0,r=0,mid=0;
        for(int i=1;i<=n;i++)
        {
            if(i<=r)
            {
                p[i]=min(p[mid*2-i],r-i+1);
            }
            while(s[i-p[i]]==s[i+p[i]])
            {
                p[i]++;
            }
            if(i+p[i]-1>=r)
            {
                r=i+p[i]-1;
                mid=i;
            }
        }
        for(int i=1;i<=n;i++)if(i==p[i]||i+p[i]-1==n)
        {
            int tmp=i+p[i]-1;
            while(tmp!=n)
            {
                // printf("tmp=%d\n",tmp);
                if(tmp+p[tmp]-1==tmp)
                {
                    break;
                }
                tmp=tmp+p[tmp]-1;
            }
            if(tmp!=n)
            {
                continue;
            }
            printf("%d ",i);
        }
        printf("\n");
    }
    return 0;
}
